@* Displays a single task card with title, assignee, priority badge, due date, and move buttons *@

<div class="card mb-2">
    <div class="card-body p-2">
        <h6 class="card-title mb-1">@Task.Title</h6>
        <p class="card-text mb-1">
            <small class="text-muted">@Task.Assignee</small>
        </p>
        <span class="badge @PriorityClass me-2">@Task.Priority</span>
        <small class="text-muted">@Task.DueDate.ToString("MMM dd")</small>
        <div class="mt-2 d-flex gap-1">
            @if (CanMoveLeft)
            {
                <button class="btn btn-outline-secondary btn-sm" @onclick="OnMoveLeft" disabled="@IsMoving">
                    &larr; Move Left
                </button>
            }
            @if (CanMoveRight)
            {
                <button class="btn btn-outline-secondary btn-sm" @onclick="OnMoveRight" disabled="@IsMoving">
                    Move Right &rarr;
                </button>
            }
        </div>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public TaskItem Task { get; set; } = default!;
    [Parameter] public bool CanMoveLeft { get; set; }
    [Parameter] public bool CanMoveRight { get; set; }
    [Parameter] public EventCallback MoveLeft { get; set; }
    [Parameter] public EventCallback MoveRight { get; set; }

    private bool IsMoving;

    private string PriorityClass => Task.Priority switch
    {
        "High" => "bg-danger",
        "Medium" => "bg-warning text-dark",
        "Low" => "bg-success",
        _ => "bg-secondary"
    };

    private async System.Threading.Tasks.Task OnMoveLeft()
    {
        IsMoving = true;
        await MoveLeft.InvokeAsync();
        IsMoving = false;
    }

    private async System.Threading.Tasks.Task OnMoveRight()
    {
        IsMoving = true;
        await MoveRight.InvokeAsync();
        IsMoving = false;
    }
}

@* Inline form for creating a new task within a column *@

<div class="card mb-2 border-primary">
    <div class="card-body p-2">
        <div class="mb-2">
            <input type="text" class="form-control form-control-sm" placeholder="Title" @bind="Title" />
        </div>
        <div class="mb-2">
            <input type="text" class="form-control form-control-sm" placeholder="Assignee" @bind="Assignee" />
        </div>
        <div class="mb-2">
            <select class="form-select form-select-sm" @bind="Priority">
                <option value="High">High</option>
                <option value="Medium">Medium</option>
                <option value="Low">Low</option>
            </select>
        </div>
        <div class="mb-2">
            <input type="date" class="form-control form-control-sm" @bind="DueDate" />
        </div>
        <div class="d-flex gap-1">
            <button class="btn btn-primary btn-sm" @onclick="OnSave" disabled="@IsSaving">Save</button>
            <button class="btn btn-secondary btn-sm" @onclick="OnCancel" disabled="@IsSaving">Cancel</button>
        </div>
        @if (!string.IsNullOrEmpty(ErrorMessage))
        {
            <div class="text-danger mt-1 small">@ErrorMessage</div>
        }
    </div>
</div>

@code {
    [Parameter, EditorRequired] public EventCallback<(string Title, string Assignee, string Priority, DateTime DueDate)> OnTaskCreate { get; set; }
    [Parameter, EditorRequired] public EventCallback OnCancelClick { get; set; }

    private string Title { get; set; } = "";
    private string Assignee { get; set; } = "";
    private string Priority { get; set; } = "Medium";
    private DateTime DueDate { get; set; } = DateTime.Today.AddDays(7);
    private bool IsSaving;
    private string? ErrorMessage;

    private async Task OnSave()
    {
        ErrorMessage = null;
        if (string.IsNullOrWhiteSpace(Title))
        {
            ErrorMessage = "Title is required.";
            return;
        }

        IsSaving = true;
        try
        {
            await OnTaskCreate.InvokeAsync((Title, Assignee, Priority, DueDate));
        }
        catch
        {
            ErrorMessage = "Failed to create task.";
        }
        finally
        {
            IsSaving = false;
        }
    }

    private async Task OnCancel() => await OnCancelClick.InvokeAsync();
}

@* A single Kanban column displaying its header, task cards, and an add-task form toggle *@

<div class="col">
    <div class="card h-100">
        <div class="card-header d-flex justify-content-between align-items-center">
            <strong>@ColumnName</strong>
            <span class="badge bg-secondary">@Tasks.Count</span>
        </div>
        <div class="card-body overflow-auto" style="max-height: 70vh;">
            @foreach (var task in Tasks)
            {
                <TaskCard Task="task"
                          CanMoveLeft="CanMoveLeft"
                          CanMoveRight="CanMoveRight"
                          MoveLeft="() => OnMoveTask.InvokeAsync((task.Id, MoveDirection.Left))"
                          MoveRight="() => OnMoveTask.InvokeAsync((task.Id, MoveDirection.Right))" />
            }

            @if (ShowAddForm)
            {
                <AddTaskForm OnTaskCreate="HandleTaskCreate" OnCancelClick="() => ShowAddForm = false" />
            }
            else
            {
                <button class="btn btn-outline-primary btn-sm w-100" @onclick="() => ShowAddForm = true">
                    + Add Task
                </button>
            }
        </div>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public string ColumnName { get; set; } = "";
    [Parameter, EditorRequired] public List<TaskItem> Tasks { get; set; } = new();
    [Parameter] public bool CanMoveLeft { get; set; }
    [Parameter] public bool CanMoveRight { get; set; }
    [Parameter] public EventCallback<(int TaskId, MoveDirection Direction)> OnMoveTask { get; set; }
    [Parameter] public EventCallback<(string Title, string Assignee, string Priority, DateTime DueDate, string Status)> OnAddTask { get; set; }

    private bool ShowAddForm;

    private async Task HandleTaskCreate((string Title, string Assignee, string Priority, DateTime DueDate) args)
    {
        await OnAddTask.InvokeAsync((args.Title, args.Assignee, args.Priority, args.DueDate, ColumnName));
        ShowAddForm = false;
    }

    public enum MoveDirection { Left, Right }
}

@* Summary statistics bar showing total, per-column, and overdue task counts *@

<div class="d-flex flex-wrap gap-3 mb-3">
    <span class="badge bg-primary fs-6">Total: @Total</span>
    <span class="badge bg-info text-dark fs-6">To Do: @ToDo</span>
    <span class="badge bg-warning text-dark fs-6">In Progress: @InProgress</span>
    <span class="badge bg-success fs-6">Done: @DoneCount</span>
    <span class="badge bg-danger fs-6">Overdue: @Overdue</span>
</div>

@code {
    [Parameter] public int Total { get; set; }
    [Parameter] public int ToDo { get; set; }
    [Parameter] public int InProgress { get; set; }
    [Parameter] public int DoneCount { get; set; }
    [Parameter] public int Overdue { get; set; }
}

@* Search input for filtering tasks by title *@

<div class="mb-3">
    <input type="text"
           class="form-control"
           placeholder="Search tasks by title..."
           value="@SearchTerm"
           @oninput="OnInput" />
</div>

@code {
    [Parameter] public string SearchTerm { get; set; } = "";
    [Parameter] public EventCallback<string> SearchTermChanged { get; set; }

    private async Task OnInput(ChangeEventArgs e)
    {
        var value = e.Value?.ToString() ?? "";
        await SearchTermChanged.InvokeAsync(value);
    }
}

