@page "/board"
@rendermode InteractiveServer
@inject ITaskService TaskService
@using static sv_fd41064e68114b768a819cc38b88608f.Components.Pages.Board.BoardColumn

<PageTitle>Kanban Board</PageTitle>

<h3 class="mb-3">Kanban Board</h3>

@if (isLoading)
{
    <div class="d-flex justify-content-center my-5">
        <div class="spinner-border" role="status">
            <span class="visually-hidden">Loading...</span>
        </div>
    </div>
}
else if (errorMessage is not null)
{
    <div class="alert alert-danger">@errorMessage</div>
}
else
{
    <BoardStatsBar Total="allTasks.Count"
                   ToDo="CountByStatus(ToDo)"
                   InProgress="CountByStatus(InProgressStatus)"
                   DoneCount="CountByStatus(Done)"
                   Overdue="allTasks.Count(t => t.DueDate < DateTime.Today)" />

    <BoardSearchBar SearchTerm="@searchTerm" SearchTermChanged="OnSearchChanged" />

    <div class="row g-3">
        <BoardColumn ColumnName="@ToDo"
                     Tasks="FilteredByStatus(ToDo)"
                     CanMoveLeft="false"
                     CanMoveRight="true"
                     OnMoveTask="HandleMoveTask"
                     OnAddTask="HandleAddTask" />

        <BoardColumn ColumnName="@InProgressStatus"
                     Tasks="FilteredByStatus(InProgressStatus)"
                     CanMoveLeft="true"
                     CanMoveRight="true"
                     OnMoveTask="HandleMoveTask"
                     OnAddTask="HandleAddTask" />

        <BoardColumn ColumnName="@Done"
                     Tasks="FilteredByStatus(Done)"
                     CanMoveLeft="true"
                     CanMoveRight="false"
                     OnMoveTask="HandleMoveTask"
                     OnAddTask="HandleAddTask" />
    </div>
}

@code {
    private const string ToDo = "To Do";
    private const string InProgressStatus = "In Progress";
    private const string Done = "Done";

    private static readonly string[] Columns = [ToDo, InProgressStatus, Done];

    private List<TaskItem> allTasks = new();
    private string searchTerm = "";
    private bool isLoading = true;
    private string? errorMessage;

    protected override async Task OnInitializedAsync()
    {
        try
        {
            allTasks = await TaskService.GetAllTasksAsync();
        }
        catch (Exception ex)
        {
            errorMessage = $"Failed to load tasks: {ex.Message}";
        }
        finally
        {
            isLoading = false;
        }
    }

    private int CountByStatus(string status) =>
        allTasks.Count(t => t.Status == status);

    private List<TaskItem> FilteredByStatus(string status) =>
        allTasks
            .Where(t => t.Status == status &&
                        (string.IsNullOrWhiteSpace(searchTerm) ||
                         t.Title.Contains(searchTerm, StringComparison.OrdinalIgnoreCase)))
            .ToList();

    private void OnSearchChanged(string term) => searchTerm = term;

    private async Task HandleMoveTask((int TaskId, MoveDirection Direction) args)
    {
        var task = allTasks.FirstOrDefault(t => t.Id == args.TaskId);
        if (task is null) return;

        var currentIndex = Array.IndexOf(Columns, task.Status);
        var newIndex = args.Direction == MoveDirection.Left ? currentIndex - 1 : currentIndex + 1;
        if (newIndex < 0 || newIndex >= Columns.Length) return;

        var newStatus = Columns[newIndex];
        try
        {
            await TaskService.UpdateTaskStatusAsync(task.Id, newStatus);
            // Replace the task in the list with updated status
            var index = allTasks.FindIndex(t => t.Id == task.Id);
            allTasks[index] = task with { Status = newStatus };
        }
        catch (Exception ex)
        {
            errorMessage = $"Failed to move task: {ex.Message}";
        }
    }

    private async Task HandleAddTask((string Title, string Assignee, string Priority, DateTime DueDate, string Status) args)
    {
        try
        {
            var created = await TaskService.CreateTaskAsync(args.Title, args.Assignee, args.Priority, args.DueDate);
            // The service may not set the status to the column's status, so ensure it matches
            allTasks.Add(created with { Status = args.Status });
        }
        catch (Exception ex)
        {
            errorMessage = $"Failed to create task: {ex.Message}";
        }
    }
}

