@* Summary statistics bar showing total, per-column, and overdue task counts *@

<div class="d-flex flex-wrap gap-3 mb-3">
    <span class="badge bg-primary fs-6">Total: @Total</span>
    <span class="badge bg-info text-dark fs-6">To Do: @ToDo</span>
    <span class="badge bg-warning text-dark fs-6">In Progress: @InProgress</span>
    <span class="badge bg-success fs-6">Done: @DoneCount</span>
    <span class="badge bg-danger fs-6">Overdue: @Overdue</span>
</div>

@code {
    [Parameter] public int Total { get; set; }
    [Parameter] public int ToDo { get; set; }
    [Parameter] public int InProgress { get; set; }
    [Parameter] public int DoneCount { get; set; }
    [Parameter] public int Overdue { get; set; }
}

@* Search input for filtering tasks by title *@

<div class="mb-3">
    <input type="text"
           class="form-control"
           placeholder="Search tasks by title..."
           value="@SearchTerm"
           @oninput="OnInput" />
</div>

@code {
    [Parameter] public string SearchTerm { get; set; } = "";
    [Parameter] public EventCallback<string> SearchTermChanged { get; set; }

    private async Task OnInput(ChangeEventArgs e)
    {
        var value = e.Value?.ToString() ?? "";
        await SearchTermChanged.InvokeAsync(value);
    }
}

@using static sv_fd41064e68114b768a819cc38b88608f.Components.Pages.Board.BoardColumn.MoveDirection

@* A single Kanban column displaying its header, task cards, and an add-task form toggle *@

<div class="col">
    <div class="card h-100">
        <div class="card-header d-flex justify-content-between align-items-center">
            <strong>@ColumnName</strong>
            <span class="badge bg-secondary">@Tasks.Count</span>
        </div>
        <div class="card-body overflow-auto" style="max-height: 70vh;">
            @foreach (var task in Tasks)
            {
                var capturedTask = task;
                <TaskCard Task="capturedTask"
                          CanMoveLeft="CanMoveLeft"
                          CanMoveRight="CanMoveRight"
                          MoveLeft="() => OnMoveTask.InvokeAsync((capturedTask.Id, Left))"
                          MoveRight="() => OnMoveTask.InvokeAsync((capturedTask.Id, Right))" />
            }

            @if (ShowAddForm)
            {
                <AddTaskForm OnTaskCreate="HandleTaskCreate" OnCancelClick="() => ShowAddForm = false" />
            }
            else
            {
                <button class="btn btn-outline-primary btn-sm w-100" @onclick="() => ShowAddForm = true">
                    + Add Task
                </button>
            }
        </div>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public string ColumnName { get; set; } = "";
    [Parameter, EditorRequired] public List<TaskItem> Tasks { get; set; } = new();
    [Parameter] public bool CanMoveLeft { get; set; }
    [Parameter] public bool CanMoveRight { get; set; }
    [Parameter] public EventCallback<(int TaskId, MoveDirection Direction)> OnMoveTask { get; set; }
    [Parameter] public EventCallback<(string Title, string Assignee, string Priority, DateTime DueDate, string Status)> OnAddTask { get; set; }

    private bool ShowAddForm;

    private async Task HandleTaskCreate((string Title, string Assignee, string Priority, DateTime DueDate) args)
    {
        await OnAddTask.InvokeAsync((args.Title, args.Assignee, args.Priority, args.DueDate, ColumnName));
        ShowAddForm = false;
    }

    public enum MoveDirection { Left, Right }
}

